type sendMail = {
  from?: string;
  subject: string;
  html: string;
  email: string;
};

export async function sendEmail({ from, email, subject, html }: sendMail) {
  const transporter = getTransporter();
  return transporter
    .sendMail({
      from: from || `<${env.EMAIL_FROM}>`,
      to: email,
      subject,
      html
    })
    .catch(err => {
      console.error(err);
      throw ApiError.badRequest("Failed to send email");
    });
}

